// Извлекаем JSON из ответа OpenAI
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content;
const prevData = $('Convert to Base64 (Purchase)').first().json;

if (!content) {
  return [{json: {error: 'empty_response', is_valid: false, ...prevData}}];
}

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  return [{json: {error: 'invalid_json', is_valid: false, ...prevData}}];
}

if (!parsed.is_purchase_receipt) {
  return [{json: {
    is_valid: false,
    is_purchase_receipt: false,
    description: parsed.description || 'Не чек покупки',
    ...prevData
  }}];
}

const amount = parsed.amount;
const minPurchase = prevData.min_purchase || 1000;
const isAmountOk = amount && amount >= minPurchase;

return [{json: {
  is_valid: true,
  is_purchase_receipt: true,
  amount: amount,
  min_purchase: minPurchase,
  is_amount_ok: isAmountOk,
  currency: parsed.currency || 'RUB',
  description: parsed.description,
  confidence: parsed.confidence,
  ...prevData
}}];

// Определяем ссылку на отчёт по банку
const taskBank = $json.task_bank || '';
const bankLinks = {
