const raw = $input.item.json.output;
let parsed;
try { parsed = JSON.parse(raw); }
catch(e) { parsed = { answer: raw, issue_with_payout: false }; }
return [{json: {
  answer: parsed.answer ?? "",
  issue_with_payout: parsed.issue_with_payout === true
}}];

